from pyspark.sql.types import StructType

def flatten_df(df, separator='_'):
    """Recursively flatten all struct columns."""
    flat_cols = []
    for field in df.schema.fields:
        if isinstance(field.dataType, StructType):
            for sub_field in field.dataType.fields:
                flat_cols.append(
                    col(f'{field.name}.{sub_field.name}')
                    .alias(f'{field.name}{separator}{sub_field.name}')
                )
        else:
            flat_cols.append(col(field.name))

    result = df.select(flat_cols)

    # Check if there are still nested structs (for deeper nesting)
    has_structs = any(
        isinstance(f.dataType, StructType) for f in result.schema.fields
    )
    if has_structs:
        return flatten_df(result, separator)
    return result

