@pandas_udf(DoubleType())
def weighted_avg(values: pd.Series, weights: pd.Series) -> float:
    """Weighted average: sum(v*w) / sum(w)"""
    mask = values.notna() & weights.notna()
    if mask.sum() == 0:
        return None
    return float((values[mask] * weights[mask]).sum() / weights[mask].sum())

