@pandas_udf(DoubleType())
def trimmed_mean(values: pd.Series) -> float:
    """Mean after removing top/bottom 5% of values."""
    clean = values.dropna()
    if len(clean) < 10:
        return float(clean.mean()) if len(clean) > 0 else None
    lower = clean.quantile(0.05)
    upper = clean.quantile(0.95)
    trimmed = clean[(clean >= lower) & (clean <= upper)]
    return float(trimmed.mean())

