@pandas_udf(DoubleType())
def tariff_cost(kw: pd.Series, customer_type: pd.Series,
                month: pd.Series) -> pd.Series:
    """Calculate tariff cost with seasonal adjustment."""
    rate_map = {'RESIDENTIAL': 0.12, 'COMMERCIAL': 0.10, 'INDUSTRIAL': 0.08}
    rate = customer_type.map(rate_map).fillna(0.15)
    winter = month.isin([12, 1, 2])
    rate = rate.where(~winter, rate * 1.25)
    return kw * rate

