def classify_consumption(kw: pd.Series) -> pd.Series:
    """Classify consumption into tiers."""
    return pd.cut(kw, bins=[0, 200, 1000, 5000, float('inf')],
                  labels=['LOW', 'MEDIUM', 'HIGH', 'EXTREME']
                  ).astype(str).replace('nan', None)

