"""Reusable data quality check functions (Module 12)."""

from dataclasses import dataclass
from typing import List
from pyspark.sql import DataFrame
from pyspark.sql.functions import col, count, when, isnan

@dataclass
class QualityResult:
    check_name: str
    passed: bool
    metric: float
    threshold: float
    detail: str

def check_null_rate(df: DataFrame, column: str, max_rate: float) -> QualityResult:
    """Verify null rate for a column is below threshold."""
    total = df.count()
    nulls = df.filter(col(column).isNull() | isnan(col(column))).count()
    rate = nulls / total if total > 0 else 0
    return QualityResult(
        f'null_rate_{column}', rate <= max_rate, rate, max_rate,
        f'{nulls}/{total} nulls ({rate:.4f})'
    )

def check_min_row_count(df: DataFrame, min_count: int) -> QualityResult:
    """Verify DataFrame has at least min_count rows."""
    actual = df.count()
    return QualityResult(
        'min_row_count', actual >= min_count, actual, min_count,
        f'{actual} rows (minimum: {min_count})'
    )

def check_referential_integrity(
    child_df: DataFrame, parent_df: DataFrame,
    key_column: str
) -> QualityResult:
    """Verify all child keys exist in parent (Module 5: anti-join)."""
    orphans = child_df.join(parent_df, key_column, 'left_anti')
    orphan_count = orphans.count()
    total = child_df.count()
    rate = orphan_count / total if total > 0 else 0
    return QualityResult(
        f'ref_integrity_{key_column}', orphan_count == 0,
        rate, 0.0, f'{orphan_count} orphan records'
    )

def check_no_duplicates(
    df: DataFrame, key_columns: List[str]
) -> QualityResult:
    """Verify no duplicate rows for given key columns."""
    total = df.count()
    distinct = df.dropDuplicates(key_columns).count()
    dupes = total - distinct
    return QualityResult(
        f'no_duplicates_{"_".join(key_columns)}', dupes == 0,
        dupes, 0, f'{dupes} duplicate rows'
    )
